// src/pages/ngo/admin/RegisterPage.jsx
import React, { useState } from 'react';
import api from '../api';

export default function RegisterNGO() {
  const [form, setForm] = useState({
    userCert: '',
    ngoId: '',
    name: '',
    regNo: '',
    address: '',
    contact: '',
    description: '',
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);

  const onChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    try {
      const res = await api.registerNGO(form);
      setMessage(res?.data || 'NGO registered successfully');
    } catch (err) {
      setMessage(err?.response?.data?.error || err.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{ maxWidth: 800, margin: '0 auto' }}>
      <div>
        <label>User Cert</label>
        <input name="userCert" value={form.userCert} onChange={onChange} />
      </div>

      <div>
        <label>NGO ID</label>
        <input name="ngoId" value={form.ngoId} onChange={onChange} />
      </div>

      <div>
        <label>Name</label>
        <input name="name" value={form.name} onChange={onChange} />
      </div>

      <div>
        <label>Reg No</label>
        <input name="regNo" value={form.regNo} onChange={onChange} />
      </div>

      <div>
        <label>Address</label>
        <input name="address" value={form.address} onChange={onChange} />
      </div>

      <div>
        <label>Contact</label>
        <input name="contact" value={form.contact} onChange={onChange} />
      </div>

      <div>
        <label>Description</label>
        <textarea name="description" value={form.description} onChange={onChange} />
      </div>

      <button type="submit" disabled={loading}>
        {loading ? 'Sending...' : 'Send Request'}
      </button>

      {message && <div style={{ marginTop: 12 }}>{String(message)}</div>}
    </form>
  );
}
